80: 	if (base < len) {
81: 		len -= base;
82: 		ret = copy_actor(desc, (char *)xdr->head[0].iov_base + base, len);
83: 		copied += ret;
84: 		if (ret != len || !desc->count)
85: 			goto out;
86: 		base = 0;
87: 	} else
88: 		base -= len;
89: 
90: 	if (unlikely(pglen == 0))
91: 		goto copy_tail;
92: 	if (unlikely(base >= pglen)) {
93: 		base -= pglen;
94: 		goto copy_tail;
95: 	}
